import { getZoomBound } from './update-plot-by-selection';
import { domainToActualRange } from '../tools/zoom-identity-by-domain';
import { isArray } from '../../../../utils/zcutils';
import { fixBrushDirection } from '../../../data-selection/chart/tools/selection-to-domain';

/**
 *
 * @param eventManager
 * @param domain
 * @param type
 * @param seriesIndex
 * @param scale
 * @param transition
 * @private
 */
export function _ZoomToDomain(eventManager, domain, type, seriesIndex, scale, transition) {
    let chart = eventManager.chart,
        plotZoom = eventManager.behaviours.PLOT_ZOOM,
        bound,
        range = type.split('').map((axisType, i) => {
            return domainToActualRange(chart, isArray(domain[0]) ? domain[i] : domain, seriesIndex, axisType);
        });

    if (type !== 'xy') {
        range = range[0];
    }

    bound = getZoomBound(range, fixBrushDirection(type, chart.axes.rotated));
    plotZoom.instance.zoomToBounds(bound, scale, transition);
}
